// MARK: - Security Manager

class SecurityManager {
    static let shared = SecurityManager()
    private let keychain = KeychainManager()
    
    private init() {}
    
    func encryptData(_ data: Data, key: SymmetricKey) throws -> Data {
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw SecurityError.encryptionFailed
        }
        return combined
    }
    
    func decryptData(_ data: Data, key: SymmetricKey) throws -> Data {
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func generateAPISignature(payload: String, secret: String) -> String {
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(signature).base64EncodedString()
    }
    
    func storeCredentials(apiKey: String, apiSecret: String) throws {
        try keychain.save(key: "apiKey", value: apiKey)
        try keychain.save(key: "apiSecret", value: apiSecret)
    }
    
    func retrieveCredentials() throws -> (apiKey: String, apiSecret: String) {
        guard let apiKey = try keychain.retrieve(key: "apiKey"),
              let apiSecret = try keychain.retrieve(key: "apiSecret") else {
            throw SecurityError.credentialsNotFound
        }
        return (apiKey, apiSecret)
    }
    
    enum SecurityError: Error {
        case encryptionFailed
        case decryptionFailed
        case credentialsNotFound
    }
}

class KeychainManager {
    func save(key: String, value: String) throws {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeychainError.saveFailed
        }
    }
    
    func retrieve(key: String) throws -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let data = result as? Data,
              let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        return value
    }
    
    enum KeychainError: Error {
        case saveFailed
        case retrieveFailed
    }
}

// MARK: - Network Manager

class NetworkManager {
    static let shared = NetworkManager()
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session: URLSession
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.waitsForConnectivity = true
        session = URLSession(configuration: config)
    }
    
    func request<T: Codable>(
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        authenticated: Bool = true
    ) -> AnyPublisher<T, Error> {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else {
            return Fail(error: NetworkError.invalidURL).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if authenticated {
            do {
                let credentials = try SecurityManager.shared.retrieveCredentials()
                let timestamp = String(Int(Date().timeIntervalSince1970))
                let payload = "\(timestamp)\(method)\(endpoint)"
                let signature = SecurityManager.shared.generateAPISignature(
                    payload: payload,
                    secret: credentials.apiSecret
                )
                
                request.setValue(credentials.apiKey, forHTTPHeaderField: "X-API-Key")
                request.setValue(signature, forHTTPHeaderField: "X-API-Signature")
                request.setValue(timestamp, forHTTPHeaderField: "X-API-Timestamp")
            } catch {
                return Fail(error: error).eraseToAnyPublisher()
            }
        }
        
        if let body = body {
            request.httpBody = body
        }
        
        return session.dataTaskPublisher(for: request)
            .tryMap { data, response -> Data in
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw NetworkError.invalidResponse
                }
                
                guard (200...299).contains(httpResponse.statusCode) else {
                    throw NetworkError.httpError(statusCode: httpResponse.statusCode)
                }
                
                return data
            }
            .decode(type: T.self, decoder: JSONDecoder.iso8601)
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    enum NetworkError: Error {
        case invalidURL
        case invalidResponse
        case httpError(statusCode: Int)
        case decodingError
    }
}

extension JSONDecoder {
    static var iso8601: JSONDecoder {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return decoder
    }
}

extension JSONEncoder {
    static var iso8601: JSONEncoder {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        return encoder
    }
}

