class TradingService {
    static let shared = TradingService()
    private let networkManager = NetworkManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    private init() {}
    
    func executeTrade(request: TradeRequest) -> AnyPublisher<Trade, Error> {
        guard let body = try? JSONEncoder.iso8601.encode(request) else {
            return Fail(error: TradingError.invalidRequest).eraseToAnyPublisher()
        }
        
        return networkManager.request(
            endpoint: "/trades",
            method: "POST",
            body: body
        )
        .map { (response: APIResponse<Trade>) -> Trade in
            guard let trade = response.data else {
                throw TradingError.executionFailed
            }
            return trade
        }
        .eraseToAnyPublisher()
    }
    
    func cancelTrade(tradeId: String) -> AnyPublisher<Bool, Error> {
        return networkManager.request(
            endpoint: "/trades/\(tradeId)/cancel",
            method: "POST"
        )
        .map { (response: APIResponse<Bool>) -> Bool in
            return response.success
        }
        .eraseToAnyPublisher()
    }
    
    func getTradeHistory(limit: Int = 50) -> AnyPublisher<[Trade], Error> {
        return networkManager.request(endpoint: "/trades?limit=\(limit)")
            .map { (response: APIResponse<[Trade]>) -> [Trade] in
                return response.data ?? []
            }
            .eraseToAnyPublisher()
    }
    
    func validateTrade(request: TradeRequest, portfolio: Portfolio) -> Result<Void, TradingError> {
        switch request.type {
        case .buy:
            let estimatedCost = (request.limitPrice ?? 0) * Decimal(request.quantity)
            if estimatedCost > portfolio.cashBalance {
                return .failure(.insufficientFunds)
            }
        case .sell:
            if let position = portfolio.positions.first(where: { $0.symbol == request.symbol }) {
                if position.quantity < request.quantity {
                    return .failure(.insufficientShares)
                }
            } else {
                return .failure(.positionNotFound)
            }
        }
        
        if request.quantity <= 0 {
            return .failure(.invalidQuantity)
        }
        
        return .success(())
    }
    
    enum TradingError: Error, LocalizedError {
        case invalidRequest
        case executionFailed
        case insufficientFunds
        case insufficientShares
        case positionNotFound
        case invalidQuantity
        
        var errorDescription: String? {
            switch self {
            case .invalidRequest: return "Invalid trade request"
            case .executionFailed: return "Trade execution failed"
            case .insufficientFunds: return "Insufficient funds"
            case .insufficientShares: return "Insufficient shares"
            case .positionNotFound: return "Position not found"
            case .invalidQuantity: return "Invalid quantity"
            }
        }
    }
}

// MARK: - Portfolio Manager

class PortfolioManager: ObservableObject {
    static let shared = PortfolioManager()
    
    @Published var portfolio: Portfolio
    @Published var isLoading = false
    @Published var error: Error?
    
    private let networkManager = NetworkManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        self.portfolio = Portfolio(positions: [], cashBalance: 0)
    }
    
    func loadPortfolio() {
        isLoading = true
        
        networkManager.request(endpoint: "/portfolio")
            .map { (response: APIResponse<Portfolio>) -> Portfolio in
                return response.data ?? Portfolio(positions: [], cashBalance: 0)
            }
            .sink(
                receiveCompletion: { [weak self] completion in
                    self?.isLoading = false
                    if case .failure(let error) = completion {
                        self?.error = error
                    }
                },
                receiveValue: { [weak self] portfolio in
                    self?.portfolio = portfolio
                }
            )
            .store(in: &cancellables)
    }
    
    func updatePosition(trade: Trade) {
        var updatedPositions = portfolio.positions
        
        if let index = updatedPositions.firstIndex(where: { $0.symbol == trade.symbol }) {
            var position = updatedPositions[index]
            
            switch trade.type {
            case .buy:
                let totalCost = position.totalCost + trade.totalValue
                let totalQuantity = position.quantity + trade.quantity
                position.quantity = totalQuantity
                position.averagePrice = totalCost / Decimal(totalQuantity)
                
            case .sell:
                position.quantity -= trade.quantity
                if position.quantity <= 0 {
                    updatedPositions.remove(at: index)
                    portfolio.positions = updatedPositions
                    return
                }
            }
            
            updatedPositions[index] = position
        } else if trade.type == .buy {
            let newPosition = Position(
                id: UUID().uuidString,
                symbol: trade.symbol,
                quantity: trade.quantity,
                averagePrice: trade.price,
                currentPrice: trade.price
            )
            updatedPositions.append(newPosition)
        }
        
        portfolio.positions = updatedPositions
    }
    
    func updateCashBalance(trade: Trade) {
        switch trade.type {
        case .buy:
            portfolio.cashBalance -= (trade.totalValue + trade.commission)
        case .sell:
            portfolio.cashBalance += (trade.totalValue - trade.commission)
        }
    }
}

